/* ─── Timeline data model & seed data  (V2) ─── */

/* ── Media ── */

export interface TimelineMedia {
  id: string;
  /** "image" now; structure ready for "video" later */
  type: "image";
  src: string;
  alt: string;
  caption?: string;
  /** Parallax speed multiplier – 0 = static, 1 = full scroll speed */
  depth: number;
  /** CSS object-position hint, e.g. "center top" */
  position?: string;
  /** CSS aspect-ratio hint, e.g. "16/9" */
  aspectHint?: string;
  /** Background opacity override (0–1) */
  opacityHint?: number;
  /** Tailwind gradient class for overlay, e.g. "from-background/80 to-transparent" */
  overlayGradient?: string;
  /** V3: explicit ordering within an event */
  sortOrder?: number;
}

/** @deprecated Use TimelineMedia — kept for V1 compat */
export type TimelineImage = TimelineMedia;

/* ── Links ── */

export interface TimelineLink {
  label: string;
  href: string;
}

/* ── Eras ── */

export interface TimelineEra {
  id: string;
  label: string;
  /** First & last event ids that belong to this era */
  startEventId: string;
  endEventId: string;
}

/* ── Events ── */

export interface TimelineEvent {
  id: string;
  start: string;
  end?: string;
  title: string;
  subtitle: string;
  category: string;
  location?: string;
  summary: string;
  body?: string;
  achievements?: string[];
  tags?: string[];
  quote?: string;
  featured?: boolean;
  /** Visual theme hint */
  theme?: "dark" | "light" | "accent";
  /** Era id this event belongs to */
  era?: string;
  /** Short milestone label shown on the track, e.g. "Founded" */
  milestone?: string;
  links?: TimelineLink[];
  /** V2 rich media array — also exposed as `images` for V1 compat */
  media: TimelineMedia[];
  /** @deprecated Alias kept for V1 — always identical to `media` */
  images: TimelineMedia[];
  /* ── V3 additions ── */
  /** URL-safe slug, defaults to id */
  slug?: string;
  /** Explicit sort position (lower = earlier) */
  sortOrder?: number;
  /** Publishing status */
  status?: "draft" | "published";
  /** ISO-8601 timestamp */
  createdAt?: string;
  /** ISO-8601 timestamp */
  updatedAt?: string;
}

