/* ── Derived helpers ── */

/** All unique categories across events */
export const timelineCategories: string[] = [
  ...new Set(timelineEvents.map((e) => e.category)),
];

/** Get events belonging to a specific era */
export function getEventsByEra(eraId: string): TimelineEvent[] {
  return timelineEvents.filter((e) => e.era === eraId);
}
